// ── CART DRAWER ───────────────────────────────────────────────────────
const CartDrawer = ({ cart, onClose, onQty, onRemove }) => {
  const [step, setStep] = useState("bag");
  const [form, setForm] = useState({ name:"", phone:"", address:"", payment:"transfer" });

  const total = cart.reduce((s,i) => s + i.price * i.qty, 0);
  const upd   = k => e => setForm(f=>({...f,[k]:e.target.value}));
  const canSend = form.name && form.phone && form.address;

  const send = () => {
    const lines = cart.map(i =>
      `• ${i.name} (${i.color} · T.${i.size}) ×${i.qty} — ${fmt(i.price * i.qty)}`
    ).join("\n");
    const pay = form.payment === "transfer"
      ? "Pago: Transferencia (te mando el alias)"
      : "Pago: MercadoPago (te mando el link)";
    const msg = encodeURIComponent(
      `🛍️ *Pedido RAME Activewear*\n\n👤 ${form.name}\n📱 ${form.phone}\n📍 ${form.address}\n\n${lines}\n\n💰 *Total: ${fmt(total)}*\n\n${pay}`
    );
    window.open(`https://wa.me/${WA}?text=${msg}`, "_blank");
    setStep("done");
  };

  return (
    <div style={{ position:"fixed", inset:0, zIndex:1000 }}>
      <div onClick={onClose} style={{ position:"absolute", inset:0, background:"rgba(30,18,8,.5)", backdropFilter:"blur(3px)" }} />
      <div style={{
        position:"absolute", right:0, top:0, bottom:0,
        width:"min(440px,100vw)", background:C.white,
        display:"flex", flexDirection:"column",
        animation:"slideR .3s cubic-bezier(.22,.61,.36,1)",
        boxShadow:"-8px 0 40px rgba(30,18,8,.14)",
      }}>
        {/* header */}
        <div style={{ padding:"24px 28px 20px", borderBottom:`1px solid ${C.creamDeep}`, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <img src={LOGO_CAMEL_ON_CREAM} alt="RAME" style={{ height:26, objectFit:"contain" }} />
          <button onClick={onClose} style={{ width:34, height:34, border:`1px solid ${C.creamDeep}`, background:"none", cursor:"pointer", color:C.mid, fontSize:15, display:"flex", alignItems:"center", justifyContent:"center" }}>✕</button>
        </div>

        {/* body */}
        <div style={{ flex:1, overflowY:"auto", padding:"20px 28px" }}>

          {step === "done" && (
            <div style={{ textAlign:"center", paddingTop:56 }} className="si">
              <div style={{ fontSize:48, marginBottom:18 }}>🤍</div>
              <div style={{ fontFamily:"'Cormorant Garamond',serif", fontSize:28, fontWeight:600, marginBottom:12 }}>¡Pedido enviado!</div>
              <p style={{ color:C.mid, lineHeight:1.8, fontSize:14 }}>
                Te escribimos por WhatsApp para coordinar el pago y la entrega. ¡Gracias por elegirnos!
              </p>
              <button className="btn-p" onClick={onClose} style={{ marginTop:32, width:"100%" }}>Cerrar</button>
            </div>
          )}

          {step === "checkout" && (
            <div style={{ display:"flex", flexDirection:"column", gap:18 }} className="fu">
              <p style={{ color:C.mid, fontSize:13, lineHeight:1.7 }}>Completá tus datos y te contactamos para coordinar el envío 🤍</p>
              <label className="field"><span>Nombre completo</span>
                <input placeholder="Tu nombre" value={form.name} onChange={upd("name")} />
              </label>
              <label className="field"><span>WhatsApp</span>
                <input placeholder="+54 9 ..." value={form.phone} onChange={upd("phone")} />
              </label>
              <label className="field"><span>Dirección de envío</span>
                <input placeholder="Calle, número, ciudad" value={form.address} onChange={upd("address")} />
              </label>
              <div>
                <span style={{ display:"block", fontSize:10, fontWeight:600, letterSpacing:".12em", textTransform:"uppercase", color:C.mid, marginBottom:12 }}>Método de pago</span>
                {[
                  { val:"transfer",    label:"Transferencia bancaria", sub:"Te enviamos el alias por WA" },
                  { val:"mercadopago", label:"MercadoPago",            sub:"Te mandamos el link de pago" },
                ].map(({ val, label, sub }) => (
                  <label key={val} onClick={() => setForm(f=>({...f,payment:val}))}
                    style={{
                      display:"flex", alignItems:"flex-start", gap:12, padding:"13px 14px",
                      marginBottom:8, border:`1px solid ${form.payment===val ? C.camel : C.creamDeep}`,
                      cursor:"pointer", transition:"border-color .2s",
                      background: form.payment===val ? C.camel+"0d" : "transparent",
                    }}>
                    <div style={{
                      width:16, height:16, borderRadius:"50%", flexShrink:0, marginTop:3,
                      border:`2px solid ${form.payment===val ? C.camel : C.camelPale}`,
                      display:"flex", alignItems:"center", justifyContent:"center",
                    }}>
                      {form.payment===val && <div style={{ width:7, height:7, borderRadius:"50%", background:C.camel }} />}
                    </div>
                    <div>
                      <div style={{ fontWeight:500, fontSize:13 }}>{label}</div>
                      <div style={{ fontSize:11, color:C.mid, marginTop:2 }}>{sub}</div>
                    </div>
                  </label>
                ))}
              </div>
            </div>
          )}

          {step === "bag" && (
            cart.length === 0 ? (
              <div style={{ textAlign:"center", paddingTop:64, color:C.muted }} className="fu">
                <img src={ISO_CAMEL_ON_CREAM} alt="" style={{ height:52, opacity:.25, marginBottom:18 }} />
                <p style={{ fontSize:14 }}>Tu carrito está vacío</p>
              </div>
            ) : (
              <div style={{ display:"flex", flexDirection:"column" }}>
                {cart.map((item, i) => (
                  <div key={i} style={{ display:"flex", gap:14, padding:"18px 0", borderBottom:`1px solid ${C.creamDeep}` }}>
                    <div style={{ width:62, height:62, flexShrink:0, background:C.cream, display:"flex", alignItems:"center", justifyContent:"center", fontSize:26 }}>👕</div>
                    <div style={{ flex:1 }}>
                      <div style={{ fontWeight:500, fontSize:14 }}>{item.name}</div>
                      <div style={{ fontSize:12, color:C.mid, marginTop:2 }}>{item.color} · Talle {item.size}</div>
                      <div style={{ fontWeight:600, color:C.camel, marginTop:5, fontSize:14 }}>{fmt(item.price)}</div>
                    </div>
                    <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", justifyContent:"space-between" }}>
                      <button onClick={() => onRemove(i)} style={{ background:"none", border:"none", cursor:"pointer", color:C.muted, fontSize:13, padding:4 }}>✕</button>
                      <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                        <button onClick={() => onQty(i,-1)} style={{ width:24, height:24, background:"none", border:`1px solid ${C.camelPale}`, cursor:"pointer", color:C.camel, fontWeight:700, display:"flex", alignItems:"center", justifyContent:"center", fontSize:14 }}>−</button>
                        <span style={{ fontSize:13, fontWeight:600, minWidth:14, textAlign:"center" }}>{item.qty}</span>
                        <button onClick={() => onQty(i,+1)} style={{ width:24, height:24, background:"none", border:`1px solid ${C.camelPale}`, cursor:"pointer", color:C.camel, fontWeight:700, display:"flex", alignItems:"center", justifyContent:"center", fontSize:14 }}>+</button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )
          )}
        </div>

        {/* footer */}
        {step !== "done" && cart.length > 0 && (
          <div style={{ padding:"20px 28px", borderTop:`1px solid ${C.creamDeep}` }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"baseline", marginBottom:18 }}>
              <span style={{ fontSize:11, letterSpacing:".1em", textTransform:"uppercase", color:C.mid }}>Total</span>
              <span style={{ fontFamily:"'Cormorant Garamond',serif", fontSize:26, fontWeight:600, color:C.camel }}>{fmt(total)}</span>
            </div>
            {step === "bag" ? (
              <button className="btn-p" style={{ width:"100%" }} onClick={() => setStep("checkout")}>Continuar →</button>
            ) : (
              <div style={{ display:"flex", gap:10 }}>
                <button className="btn-o" style={{ flex:1 }} onClick={() => setStep("bag")}>← Volver</button>
                <button className="btn-p" style={{ flex:2 }} onClick={send} disabled={!canSend}>Confirmar pedido</button>
              </div>
            )}
            <p style={{ textAlign:"center", fontSize:11, color:C.muted, marginTop:14, letterSpacing:".04em" }}>
              Coordinamos envío y pago por WhatsApp 🤍
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

// ── MODAL PRODUCTO ────────────────────────────────────────────────────
const ProductModal = ({ product:p, onClose, onAdd }) => {
  const [color, setColor] = useState(p.variants[0].color);
  const [size,  setSize]  = useState(null);
  const [flash, setFlash] = useState(false);

  const variant = p.variants.find(v => v.color === color);
  const stock   = size ? variant.sizes[size] : null;

  const add = () => {
    if (!size || stock === 0) return;
    onAdd({ ...p, color, size });
    setFlash(true);
    setTimeout(() => { setFlash(false); onClose(); }, 900);
  };

  return (
    <div style={{ position:"fixed", inset:0, zIndex:900, display:"flex", alignItems:"center", justifyContent:"center", padding:20 }}>
      <div onClick={onClose} style={{ position:"absolute", inset:0, background:"rgba(30,18,8,.55)", backdropFilter:"blur(4px)" }} />
      <div className="si" style={{ position:"relative", background:C.white, width:"100%", maxWidth:500, maxHeight:"90vh", overflowY:"auto", boxShadow:"0 24px 64px rgba(30,18,8,.2)" }}>
        <div style={{ height:240, background:`linear-gradient(150deg,${C.cream},${C.creamDeep})`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:68, position:"relative" }}>
          👕
          <button onClick={onClose} style={{ position:"absolute", top:14, right:14, width:34, height:34, background:C.white, border:"none", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", color:C.mid, fontSize:15, boxShadow:"0 2px 10px rgba(0,0,0,.1)" }}>✕</button>
        </div>
        <div style={{ padding:"24px 28px 32px" }}>
          <div style={{ fontSize:10, letterSpacing:".15em", textTransform:"uppercase", color:C.muted, marginBottom:8 }}>{p.category}</div>
          <div style={{ fontFamily:"'Cormorant Garamond',serif", fontSize:28, fontWeight:600, lineHeight:1.15, marginBottom:8 }}>{p.name}</div>
          <p style={{ color:C.mid, lineHeight:1.7, fontSize:13, marginBottom:22 }}>{p.description}</p>

          {/* color */}
          <div style={{ marginBottom:20 }}>
            <div style={{ fontSize:10, letterSpacing:".12em", textTransform:"uppercase", color:C.mid, marginBottom:10 }}>
              Color — <span style={{ color:C.dark, fontWeight:500 }}>{color}</span>
            </div>
            <div style={{ display:"flex", gap:8 }}>
              {p.variants.map(v => (
                <button key={v.color} onClick={() => { setColor(v.color); setSize(null); }}
                  style={{ padding:"8px 18px", border:`1px solid ${color===v.color ? C.camel : C.camelPale}`, background:color===v.color ? C.camel+"18" : "transparent", cursor:"pointer", fontFamily:"'Jost',sans-serif", fontWeight:500, fontSize:12, color:color===v.color ? C.camel : C.mid, transition:"all .18s", letterSpacing:".04em" }}>
                  {v.color}
                </button>
              ))}
            </div>
          </div>

          {/* talle */}
          <div style={{ marginBottom:26 }}>
            <div style={{ fontSize:10, letterSpacing:".12em", textTransform:"uppercase", color:C.mid, marginBottom:10 }}>Talle</div>
            <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
              {Object.entries(variant.sizes).map(([sz, qty]) => (
                <button key={sz} onClick={() => qty > 0 && setSize(sz)} disabled={qty===0}
                  style={{ width:46, height:46, border:`1px solid ${size===sz ? C.camel : qty===0 ? C.cream : C.camelPale}`, background:size===sz ? C.camel : qty===0 ? C.cream : C.white, color:size===sz ? C.white : qty===0 ? C.camelPale : C.dark, cursor:qty===0 ? "not-allowed" : "pointer", fontFamily:"'Jost',sans-serif", fontWeight:500, fontSize:12, transition:"all .18s" }}>
                  {sz}
                </button>
              ))}
            </div>
            {size && stock !== null && (
              <p style={{ marginTop:8, fontSize:11, color:stock<=2 ? C.warn : C.ok }}>
                {stock===0 ? "Sin stock" : stock<=2 ? `¡Solo quedan ${stock}!` : "Disponible"}
              </p>
            )}
          </div>

          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
            <div style={{ fontFamily:"'Cormorant Garamond',serif", fontSize:28, fontWeight:600, color:C.camel }}>{fmt(p.price)}</div>
            <button className="btn-p" onClick={add} disabled={!size || stock===0}>
              {flash ? "✓ Agregado" : "Agregar al carrito"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

