// ── AGREGAR PRODUCTO ──────────────────────────────────────────────────
const AddProduct = ({ onSave, onCancel }) => {
  const [f, setF]       = useState({ name:"", category:"Calzas", price:"", description:"", featured:false });
  const [colors, setCols] = useState([{ color:"", sizes:{XS:0,S:0,M:0,L:0,XL:0} }]);
  const upd = k => e => setF(p=>({...p,[k]:e.target.value}));
  const addCol = () => setCols(c=>[...c,{ color:"",sizes:{XS:0,S:0,M:0,L:0,XL:0} }]);
  const updColName  = (i,v) => setCols(c=>c.map((x,xi)=>xi===i?{...x,color:v}:x));
  const updColStock = (i,sz,v) => setCols(c=>c.map((x,xi)=>xi===i?{...x,sizes:{...x.sizes,[sz]:Math.max(0,parseInt(v)||0)}}:x));

  return (
    <div className="fu">
      <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:28 }}>
        <button onClick={onCancel} style={{ width:34,height:34,border:`1px solid ${C.creamDeep}`,background:"none",cursor:"pointer",color:C.mid,fontSize:15,display:"flex",alignItems:"center",justifyContent:"center" }}>←</button>
        <h2 style={{ fontFamily:"'Cormorant Garamond',serif", fontSize:28 }}>Nuevo producto</h2>
      </div>
      <div style={{ background:C.white, border:`1px solid ${C.creamDeep}`, padding:"28px 32px", maxWidth:580 }}>
        <div style={{ display:"flex", flexDirection:"column", gap:18 }}>
          <label className="field"><span>Nombre</span>
            <input value={f.name} onChange={upd("name")} placeholder="Ej: Calza Cintura Alta" />
          </label>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:16 }}>
            <label className="field"><span>Categoría</span>
              <select value={f.category} onChange={upd("category")}>
                {["Calzas","Tops","Buzos","Shorts","Sets","Accesorios"].map(c=><option key={c}>{c}</option>)}
              </select>
            </label>
            <label className="field"><span>Precio ARS</span>
              <input type="number" value={f.price} onChange={upd("price")} placeholder="18500" />
            </label>
          </div>
          <label className="field"><span>Descripción</span>
            <textarea value={f.description} onChange={upd("description")} rows={3} placeholder="Descripción del producto..." style={{ resize:"vertical" }} />
          </label>
          <div>
            <div style={{ fontSize:10,fontWeight:600,letterSpacing:".12em",textTransform:"uppercase",color:C.mid,marginBottom:12 }}>Colores y stock</div>
            {colors.map((v,vi)=>(
              <div key={vi} style={{ background:C.cream,padding:"14px 16px",marginBottom:10 }}>
                <label className="field" style={{ marginBottom:10 }}><span>Color</span>
                  <input value={v.color} onChange={e=>updColName(vi,e.target.value)} placeholder="Ej: Negro" />
                </label>
                <div style={{ display:"flex",gap:10,flexWrap:"wrap" }}>
                  {Object.keys(v.sizes).map(sz=>(
                    <div key={sz}>
                      <div style={{ fontSize:9,fontWeight:600,letterSpacing:".1em",color:C.muted,marginBottom:5,textAlign:"center" }}>{sz}</div>
                      <input type="number" min="0" value={v.sizes[sz]} onChange={e=>updColStock(vi,sz,e.target.value)} style={{ width:50,textAlign:"center",padding:"8px 4px" }} />
                    </div>
                  ))}
                </div>
              </div>
            ))}
            <button className="btn-g" style={{ fontSize:10 }} onClick={addCol}>+ Agregar color</button>
          </div>
          <label style={{ display:"flex",alignItems:"center",gap:10,cursor:"pointer" }}>
            <input type="checkbox" checked={f.featured} onChange={e=>setF(p=>({...p,featured:e.target.checked}))} />
            <span style={{ fontSize:13,fontWeight:500 }}>Marcar como destacado</span>
          </label>
          <div style={{ display:"flex",gap:10,paddingTop:6 }}>
            <button className="btn-o" onClick={onCancel}>Cancelar</button>
            <button className="btn-p" onClick={() => { if(!f.name||!f.price) return alert("Completá nombre y precio"); onSave({...f,price:parseInt(f.price),variants:colors,image:null}); }}>Guardar producto</button>
          </div>
        </div>
      </div>
    </div>
  );
};

// ── APP ROOT ──────────────────────────────────────────────────────────
export default function App() {
  const [products, setProducts] = useState(DEMO_PRODUCTS);
  const [cart, setCart]         = useState([]);
  const [cartOpen, setCartOpen] = useState(false);
  const [mode, setMode]         = useState("store");
  const [adminOk, setAdminOk]   = useState(false);

  const addToCart = useCallback(item => {
    setCart(prev => {
      const idx = prev.findIndex(i => i.id===item.id && i.color===item.color && i.size===item.size);
      if (idx >= 0) { const n=[...prev]; n[idx]={...n[idx],qty:n[idx].qty+1}; return n; }
      return [...prev, {...item, qty:1}];
    });
    setCartOpen(true);
  }, []);

  return (
    <>
      <GS />
      {mode==="adminLogin" && (
        <AdminLogin onLogin={() => { setAdminOk(true); setMode("admin"); }} />
      )}
      {mode==="admin" && adminOk && (
        <Admin products={products} setProducts={setProducts} onExit={() => setMode("store")} />
      )}
      {mode==="store" && (
        <>
          <Store products={products} cart={cart} onAdd={addToCart} onOpenCart={() => setCartOpen(true)} />
          {cartOpen && (
            <CartDrawer
              cart={cart}
              onClose={() => setCartOpen(false)}
              onQty={(i,d) => setCart(prev => { const n=[...prev]; n[i]={...n[i],qty:Math.max(1,n[i].qty+d)}; return n; })}
              onRemove={i => setCart(prev => prev.filter((_,xi)=>xi!==i))}
            />
          )}
          {/* botón admin discreto, sin mostrar contraseña */}
          <button onClick={() => setMode("adminLogin")} style={{ position:"fixed",bottom:20,right:20,background:C.dark,color:"#4A3020",border:"none",padding:"9px 16px",fontFamily:"'Jost',sans-serif",fontSize:10,letterSpacing:".1em",textTransform:"uppercase",cursor:"pointer",opacity:.55 }}>
            ⚙ Admin
          </button>
        </>
      )}
    </>
  );
}
